import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
} from "react-router-dom";
import Cookies from "js-cookie";
import axios from "axios";
import { useState, useEffect } from "react";

import PermissionContext from "./context/PermissionContext";
import ProtectedRoute from "./components/ProtectedRoute";

import AdminLogin from "./pages/AdminLogin";
import Dashboard from "./pages/Dashboard";
import MyProfile from "./pages/MyProfile";
import UserManagement from "./pages/UserManagement";
import PaymentsManagement from "./pages/PaymentsManagement";
import EmployeeManagement from "./pages/EmployeeManagement";
import UserDetails from "./pages/UserDetails";
import SupportManagement from "./pages/SupportManagement";
import RoleManagement from "./pages/RoleManagement";
import PermissionManagement from "./pages/PermissionManagement";
import ProtectedLayout from "./layouts/ProtectedLayout";

function App() {
  const [permissions, setPermissions] = useState(() => {
    const stored = localStorage.getItem("permissions");
    return stored ? JSON.parse(stored) : [];
  });

  const [isAuthenticated, setIsAuthenticated] = useState(
    !!Cookies.get("adminToken"),
  );

  useEffect(() => {
    const token = Cookies.get("adminToken");
    setIsAuthenticated(!!token);
  }, []);

  const refreshUser = async () => {
    try {
      const token = Cookies.get("adminToken");
      if (!token) return;

      const res = await axios.get(
        `${API_BASE_URL}/admin/me`,
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      const user = res.data.user || {};
      const updatedPermissions = user.permissions || [];

      // 🔥 Update React state
      setPermissions(updatedPermissions);

      // 🔥 Update localStorage
      localStorage.setItem(
        "permissions",
        JSON.stringify(updatedPermissions)
      );
      localStorage.setItem("user", JSON.stringify(user));

    } catch (err) {
      console.error("Failed to refresh user:", err);
    }
  };


  function ScrollToTop() {
    const { pathname } = useLocation();

    useEffect(() => {
      window.scrollTo(0, 0);
    }, [pathname]);

    return null;
  }

  return (
    <PermissionContext.Provider value={{ permissions, setPermissions }}>
      <BrowserRouter>
        <ScrollToTop />

        <Routes>
          {/* Login */}
          <Route
            path="/"
            element={
              <AdminLogin
                setAuth={setIsAuthenticated}
                setPermissions={setPermissions}
              />
            }
          />

          {/* Protected Routes */}
          <Route element={<ProtectedLayout />}>
            <Route
              path="/dashboard"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <Dashboard />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/myprofile"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <MyProfile />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/users"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewUser">
                    <UserManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/users/:userId"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewUser">
                    <UserDetails />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/payment"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewPayment">
                    <PaymentsManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/support"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewSupport">
                    <SupportManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/employee"
              element={
                isAuthenticated ? (
                  <ProtectedRoute requiredPermission="viewEmployee">
                    <EmployeeManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/roles"
              element={
                isAuthenticated ? (
                  <ProtectedRoute adminOnly>
                    <RoleManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/permissions"
              element={
                isAuthenticated ? (
                  <ProtectedRoute adminOnly>
                    <PermissionManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />
          </Route>

          {/* 404 */}
          <Route path="*" element={<div>404 - Page not found</div>} />
        </Routes>
      </BrowserRouter>
    </PermissionContext.Provider>
  );
}

export default App;
